@import url("https://fonts.googleapis.com/css2?family=Figtree:wght@400;600;700&display=swap");
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  font-family: "Figtree", sans-serif;
  background: transparent;
  padding: 0.75rem;
  font-size: 13px;
  color: #05042E;
}

.card {
  background: #fff;
  border: 0.5px solid rgba(0, 0, 0, 0.12);
  border-radius: 12px;
  overflow: hidden;
}

.card-header {
  background: #469BC0;
  padding: 0.6rem 1.25rem;
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.card-title {
  font-size: 11px;
  font-weight: 700;
  color: #fff;
  text-transform: uppercase;
  letter-spacing: 0.07em;
}

.card-body {
  padding: 1rem 1.25rem;
  display: flex;
  flex-direction: column;
  gap: 0;
}

.field-row {
  display: flex;
  gap: 10px;
  align-items: flex-end;
  flex-wrap: nowrap;
}

.fg {
  display: flex;
  flex-direction: column;
  gap: 4px;
  flex: 1;
  min-width: 0;
}

.fg.narrow {
  flex: 0 0 70px;
}

.fg.wide {
  flex: 1.5;
}

.fg.fixed {
  flex: 0 0 auto;
}

label {
  font-size: 10px;
  font-weight: 600;
  color: #888780;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  white-space: nowrap;
}

.req {
  color: #A3E851;
}

select, input[type=text], input[type=number] {
  font-size: 13px;
  font-family: "Figtree", sans-serif;
  border: 0.5px solid rgba(0, 0, 0, 0.15);
  border-radius: 6px;
  padding: 7px 10px;
  color: #05042E;
  outline: none;
  width: 100%;
  background: #fff;
  height: 34px;
}

select:focus, input:focus {
  border-color: #469BC0;
}

select:disabled {
  background: #f5f5f5;
  color: #aaa;
  cursor: not-allowed;
}

.switch {
  position: relative;
  display: inline-block;
  width: 38px;
  height: 20px;
}

.switch input {
  opacity: 0;
  width: 0;
  height: 0;
}

.slider {
  position: absolute;
  cursor: pointer;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: #E0DFE1;
  border-radius: 20px;
  transition: 0.3s;
}

.slider:before {
  position: absolute;
  content: "";
  height: 14px;
  width: 14px;
  left: 3px;
  bottom: 3px;
  background: white;
  border-radius: 50%;
  transition: 0.3s;
}

input[type=checkbox]:checked + .slider {
  background: #469BC0;
}

input[type=checkbox]:checked + .slider:before {
  transform: translateX(18px);
}

.btn {
  font-size: 12px;
  font-weight: 700;
  padding: 0 14px;
  border-radius: 6px;
  border: none;
  cursor: pointer;
  font-family: "Figtree", sans-serif;
  white-space: nowrap;
  height: 34px;
}

.btn-add {
  background: #A3E851;
  color: #05042E;
}

.btn-add:hover {
  background: #5DC987;
}

.btn-confirm {
  background: #05042E;
  color: #A3E851;
}

.btn-confirm:hover {
  background: #469BC0;
  color: #fff;
}

.btn-nm {
  font-size: 10px;
  font-weight: 600;
  padding: 2px 8px;
  border-radius: 20px;
  border: none;
  cursor: pointer;
  background: #05042E;
  color: #A3E851;
  font-family: "Figtree", sans-serif;
  margin-left: 6px;
}

.btn-nm:hover {
  background: #469BC0;
  color: #fff;
}

.btn-nm:disabled {
  background: #E0DFE1;
  color: #aaa;
  cursor: not-allowed;
}

.divider {
  border: none;
  border-top: 0.5px solid rgba(0, 0, 0, 0.1);
  margin: 1rem 0;
}

.bottom-row {
  display: flex;
  align-items: center;
  justify-content: flex-end;
  gap: 12px;
}

.summary {
  display: flex;
  align-items: center;
  gap: 16px;
  flex: 1;
}

.pill {
  display: flex;
  align-items: center;
  gap: 6px;
}

.pill-icon {
  width: 22px;
  height: 22px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 12px;
}

.matched-icon {
  background: #dcfce7;
  color: #16a34a;
}

.unmatched-icon {
  background: #fef9c3;
  color: #ca8a04;
}

.pill-count {
  font-size: 18px;
  font-weight: 700;
  color: #05042E;
}

.pill-lbl {
  font-size: 10px;
  font-weight: 600;
  color: #888780;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.err {
  font-size: 11px;
  color: #dc2626;
  margin-top: 2px;
  display: none;
}

.has-err select, .has-err input {
  border-color: #dc2626 !important;
}

.toggle-wrap {
  display: flex;
  align-items: center;
  height: 34px;
}

