var _lastItemTypeCount = 0;
function pop(id, items, lk, vk) {
  var s = document.getElementById(id);
  var cur = s.value;
  s.innerHTML = '<option value="">-- Select --</option>';
  (items || []).forEach(function (r) {
    var o = document.createElement('option');
    o.value = r[vk];
    o.textContent = r[lk];
    s.appendChild(o);
  });
  if (cur) s.value = cur;
}
function clrErr(g) {
  var el = document.getElementById(g);
  if (el) el.classList.remove('has-err');
  var e = el ? el.querySelector('.err') : null;
  if (e) e.style.display = 'none';
}
function shErr(g, e) {
  var el = document.getElementById(g);
  if (el) el.classList.add('has-err');
  var er = document.getElementById(e);
  if (er) er.style.display = 'block';
}
function reset() {
  document.getElementById('s-type').value = '';
  document.getElementById('s-make').innerHTML = '<option value="">-- Select --</option>';
  document.getElementById('s-make').disabled = true;
  document.getElementById('s-model').innerHTML = '<option value="">-- Select --</option>';
  document.getElementById('s-model').disabled = true;
  document.getElementById('btn-nm').disabled = true;
  document.getElementById('i-serial').value = '';
  document.getElementById('i-qty').value = '1';
  document.getElementById('i-tag').value = '';
  document.getElementById('tog').checked = false;
}
function validate() {
  var ok = true;
  if (!document.getElementById('s-type').value) {
    shErr('fg1', 'e-type');
    ok = false;
  }
  if (!document.getElementById('s-make').value) {
    shErr('fg2', 'e-make');
    ok = false;
  }
  if (!document.getElementById('s-model').value) {
    shErr('fg3', 'e-model');
    ok = false;
  }
  return ok;
}
appsmith.onReady(function () {
  var m = appsmith.model;
  if (m.itemTypes && m.itemTypes.length) {
    _lastItemTypeCount = m.itemTypes.length;
    pop('s-type', m.itemTypes, 'item_type_name', 'item_type_id');
  }
  if (m.makes && m.makes.length) {
    pop('s-make', m.makes, 'make_name', 'make_id');
    document.getElementById('s-make').disabled = false;
  }
  if (m.models && m.models.length) {
    pop('s-model', m.models, 'model_name', 'model_id');
    document.getElementById('s-model').disabled = false;
    document.getElementById('btn-nm').disabled = false;
  }
  document.getElementById('c-matched').textContent = m.matchedCount || 0;
  document.getElementById('c-unmatched').textContent = m.unmatchedCount || 0;
  document.getElementById('s-type').addEventListener('change', function () {
    var v = this.value;
    var db = false;
    var types = appsmith.model.itemTypes || [];
    var found = types.find(function (t) {
      return String(t.item_type_id) === String(v);
    });
    if (found) db = !!found.is_data_bearing;
    document.getElementById('tog').checked = db;
    clrErr('fg1');
    document.getElementById('s-make').innerHTML = '<option value="">-- Select --</option>';
    document.getElementById('s-make').disabled = !v;
    document.getElementById('s-model').innerHTML = '<option value="">-- Select --</option>';
    document.getElementById('s-model').disabled = true;
    document.getElementById('btn-nm').disabled = true;
    appsmith.updateModel({
      selectedItemTypeId: v,
      isDataBearing: db
    });
    appsmith.triggerEvent('onItemTypeChange');
  });
  document.getElementById('s-make').addEventListener('change', function () {
    var v = this.value;
    clrErr('fg2');
    document.getElementById('s-model').innerHTML = '<option value="">-- Select --</option>';
    document.getElementById('s-model').disabled = !v;
    document.getElementById('btn-nm').disabled = !v;
    appsmith.updateModel({
      selectedMakeId: v
    });
    appsmith.triggerEvent('onMakeChange');
  });
  document.getElementById('s-model').addEventListener('change', function () {
    clrErr('fg3');
    appsmith.updateModel({
      selectedModelId: this.value
    });
  });
  document.getElementById('tog').addEventListener('change', function () {
    appsmith.updateModel({
      isDataBearing: this.checked
    });
  });
  document.getElementById('btn-nm').addEventListener('click', function () {
    appsmith.triggerEvent('onNewModel');
  });
  document.getElementById('btn-add').addEventListener('click', function () {
    if (!validate()) return;
    appsmith.updateModel({
      asset: {
        item_type_id: document.getElementById('s-type').value,
        make_id: document.getElementById('s-make').value,
        model_id: document.getElementById('s-model').value,
        serial_no: document.getElementById('i-serial').value.trim(),
        qty: parseInt(document.getElementById('i-qty').value) || 1,
        asset_tag: document.getElementById('i-tag').value.trim(),
        is_data_bearing: document.getElementById('tog').checked
      }
    });
    appsmith.triggerEvent('onAddAsset');
    setTimeout(function () {
      reset();
    }, 1500);
  });
  document.getElementById('btn-confirm').addEventListener('click', function () {
    appsmith.triggerEvent('onConfirmAssets');
  });
});
appsmith.onModelChange(function () {
  var m = appsmith.model;
  if (m.itemTypes && m.itemTypes.length && m.itemTypes.length !== _lastItemTypeCount) {
    _lastItemTypeCount = m.itemTypes.length;
    var curType = document.getElementById('s-type').value;
    pop('s-type', m.itemTypes, 'item_type_name', 'item_type_id');
    if (curType) document.getElementById('s-type').value = curType;
  }
  if (m.makes && m.makes.length) {
    var curMake = document.getElementById('s-make').value;
    pop('s-make', m.makes, 'make_name', 'make_id');
    document.getElementById('s-make').disabled = false;
    if (curMake) document.getElementById('s-make').value = curMake;
  }
  if (m.models && m.models.length) {
    var curModel = document.getElementById('s-model').value;
    pop('s-model', m.models, 'model_name', 'model_id');
    document.getElementById('s-model').disabled = false;
    document.getElementById('btn-nm').disabled = false;
    if (curModel) document.getElementById('s-model').value = curModel;
  }
  if (typeof m.matchedCount !== 'undefined') {
    document.getElementById('c-matched').textContent = m.matchedCount;
  }
  if (typeof m.unmatchedCount !== 'undefined') {
    document.getElementById('c-unmatched').textContent = m.unmatchedCount;
  }
  if (m.resetForm) reset();
});

